() => {
  const out = {url: location.href, scriptSrcPixels: [], perfPixels: [], fbqStatePixels: null, fbqInstancePixels: null, hasFbq: false, errs: []};
  const re = /connect\.facebook\.net\/signals\/config\/(\d+)/;
  try {
    [...document.querySelectorAll('script')].forEach(s => { const m=(s.src||'').match(re); if(m) out.scriptSrcPixels.push(m[1]); });
  } catch(e){ out.errs.push('scripts:'+e); }
  try {
    (performance.getEntriesByType('resource')||[]).forEach(en => { const m=(en.name||'').match(re); if(m) out.perfPixels.push(m[1]); });
  } catch(e){ out.errs.push('perf:'+e); }
  try {
    out.hasFbq = (typeof window.fbq === 'function');
    if (window.fbq && typeof window.fbq.getState === 'function') {
      const st = window.fbq.getState();
      out.fbqStatePixels = (st && st.pixels ? st.pixels.map(p=>p.id) : null);
    }
  } catch(e){ out.errs.push('getState:'+e); }
  try {
    if (window.fbq && window.fbq.instance && window.fbq.instance.pixelsByID) {
      out.fbqInstancePixels = Object.keys(window.fbq.instance.pixelsByID);
    }
  } catch(e){ out.errs.push('instance:'+e); }
  out.scriptSrcPixels = [...new Set(out.scriptSrcPixels)];
  out.perfPixels = [...new Set(out.perfPixels)];
  return out;
}

